import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Divider,
  InputAdornment,
  IconButton,
  Tooltip,
  Alert,
  Snackbar,
  Switch,
  FormControlLabel,
  Tabs,
  Tab
} from '@mui/material';
import {
  Save,
  Image,
  ColorLens,
  Visibility,
  Email,
  Phone,
  Title,
  ViewModule,
  Favorite,
  Badge,
  Money
} from '@mui/icons-material';
import { useFirebase } from '../../context/FirebaseContext';
import { AppSettings } from '../../types';
import ColorPicker from '../ColorPicker';
import Grid from '../utils/CustomGrid';

// Расширим интерфейс AppSettings с настройками для карточек
interface ExtendedAppSettings extends AppSettings {
  cardSettings?: {
    enableFavorites?: boolean;
    showCompanyLogo?: boolean;
    showPrice?: boolean;
    showProgress?: boolean;
    cornerRadius?: string;
    enableHoverEffects?: boolean;
    cardElevation?: string;
  }
}

const initialSettings: Partial<ExtendedAppSettings> = {
  appName: '',
  logoUrl: '',
  heroImageUrl: '',
  primaryColor: '#1976D2',
  secondaryColor: '#2196F3',
  contactEmail: '',
  contactPhone: '',
  cardSettings: {
    enableFavorites: true,
    showCompanyLogo: true,
    showPrice: true,
    showProgress: true,
    cornerRadius: '20px',
    enableHoverEffects: true,
    cardElevation: 'medium'
  }
};

// Компонент для отображения вкладок настроек
interface TabPanelProps {
  children?: React.ReactNode;
  index: number;
  value: number;
}

function TabPanel(props: TabPanelProps) {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`settings-tabpanel-${index}`}
      aria-labelledby={`settings-tab-${index}`}
      {...other}
    >
      {value === index && (
        <Box sx={{ pt: 3 }}>
          {children}
        </Box>
      )}
    </div>
  );
}

const AppSettingsForm: React.FC = () => {
  const { appSettings, updateSettings } = useFirebase();
  const [settings, setSettings] = useState<Partial<ExtendedAppSettings>>(initialSettings);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState(0);

  // Загрузка настроек при монтировании компонента
  useEffect(() => {
    if (appSettings) {
      setSettings({
        appName: appSettings.appName || '',
        logoUrl: appSettings.logoUrl || '',
        heroImageUrl: appSettings.heroImageUrl || '',
        primaryColor: appSettings.primaryColor || '#1976D2',
        secondaryColor: appSettings.secondaryColor || '#2196F3',
        contactEmail: appSettings.contactEmail || '',
        contactPhone: appSettings.contactPhone || '',
        cardSettings: {
          enableFavorites: appSettings.cardSettings?.enableFavorites ?? true,
          showCompanyLogo: appSettings.cardSettings?.showCompanyLogo ?? true,
          showPrice: appSettings.cardSettings?.showPrice ?? true,
          showProgress: appSettings.cardSettings?.showProgress ?? true,
          cornerRadius: appSettings.cardSettings?.cornerRadius || '20px',
          enableHoverEffects: appSettings.cardSettings?.enableHoverEffects ?? true,
          cardElevation: appSettings.cardSettings?.cardElevation || 'medium'
        }
      });
    }
  }, [appSettings]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setSettings(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleCardSettingChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, checked, type } = e.target;
    setSettings(prev => ({
      ...prev,
      cardSettings: {
        ...prev.cardSettings,
        [name]: type === 'checkbox' ? checked : value
      }
    }));
  };

  const handleTabChange = (_: React.SyntheticEvent, newValue: number) => {
    setActiveTab(newValue);
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      setError(null);
      
      const result = await updateSettings(settings);
      
      if (result) {
        setSuccess(true);
      } else {
        setError('Произошла ошибка при сохранении настроек');
      }
    } catch (err) {
      console.error('Ошибка при сохранении настроек:', err);
      setError('Произошла ошибка при сохранении настроек');
    } finally {
      setLoading(false);
    }
  };

  const handleCloseSnackbar = () => {
    setSuccess(false);
  };

  const previewImage = (url: string) => {
    if (!url) return;
    window.open(url, '_blank');
  };

  return (
    <Paper sx={{ p: 3, borderRadius: 2, mb: 4 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Typography variant="h5" component="h2">
          Настройки приложения
        </Typography>
        <Button
          variant="contained"
          color="primary"
          startIcon={<Save />}
          onClick={handleSave}
          disabled={loading}
        >
          Сохранить
        </Button>
      </Box>
      
      <Tabs 
        value={activeTab} 
        onChange={handleTabChange} 
        aria-label="settings tabs"
        sx={{ borderBottom: 1, borderColor: 'divider' }}
      >
        <Tab icon={<Title />} iconPosition="start" label="Основные" />
        <Tab icon={<ViewModule />} iconPosition="start" label="Карточки розыгрышей" />
      </Tabs>
      
      <TabPanel value={activeTab} index={0}>
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 3 }}>
          {/* Основные настройки */}
          <Box sx={{ flex: '1 1 350px', minWidth: '300px' }}>
            <Typography variant="h6" gutterBottom>
              Основные настройки
            </Typography>
            
            <TextField
              fullWidth
              label="Название приложения"
              name="appName"
              value={settings.appName}
              onChange={handleChange}
              margin="normal"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Title />
                  </InputAdornment>
                )
              }}
            />
            
            <TextField
              fullWidth
              label="URL логотипа"
              name="logoUrl"
              value={settings.logoUrl}
              onChange={handleChange}
              margin="normal"
              helperText="URL изображения логотипа, которое будет отображаться в шапке"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Image />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <Tooltip title="Просмотреть изображение">
                      <IconButton 
                        edge="end" 
                        onClick={() => previewImage(settings.logoUrl || '')}
                        disabled={!settings.logoUrl}
                      >
                        <Visibility />
                      </IconButton>
                    </Tooltip>
                  </InputAdornment>
                )
              }}
            />
            
            <TextField
              fullWidth
              label="URL изображения героя"
              name="heroImageUrl"
              value={settings.heroImageUrl}
              onChange={handleChange}
              margin="normal"
              helperText="URL изображения для главного баннера на домашней странице"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Image />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <Tooltip title="Просмотреть изображение">
                      <IconButton 
                        edge="end" 
                        onClick={() => previewImage(settings.heroImageUrl || '')}
                        disabled={!settings.heroImageUrl}
                      >
                        <Visibility />
                      </IconButton>
                    </Tooltip>
                  </InputAdornment>
                )
              }}
            />
          </Box>
          
          {/* Цвета и контакты */}
          <Box sx={{ flex: '1 1 350px', minWidth: '300px' }}>
            <Typography variant="h6" gutterBottom>
              Цвета и контакты
            </Typography>
            
            <ColorPicker
              color={settings.primaryColor || '#1976D2'}
              onChange={(color) => setSettings(prev => ({ ...prev, primaryColor: color }))}
              label="Основной цвет"
            />
            
            <ColorPicker
              color={settings.secondaryColor || '#2196F3'}
              onChange={(color) => setSettings(prev => ({ ...prev, secondaryColor: color }))}
              label="Вторичный цвет"
            />
            
            <TextField
              fullWidth
              label="Контактный Email"
              name="contactEmail"
              value={settings.contactEmail}
              onChange={handleChange}
              margin="normal"
              type="email"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email />
                  </InputAdornment>
                )
              }}
            />
            
            <TextField
              fullWidth
              label="Контактный телефон"
              name="contactPhone"
              value={settings.contactPhone}
              onChange={handleChange}
              margin="normal"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Phone />
                  </InputAdornment>
                )
              }}
            />
          </Box>
        </Box>
      </TabPanel>
      
      <TabPanel value={activeTab} index={1}>
        <Typography variant="h6" gutterBottom mb={3}>
          Настройки отображения карточек розыгрышей
        </Typography>
        
        <Grid container spacing={3}>
          <Grid size={{ xs: 12, md: 6 }}>
            <Paper sx={{ p: 3, borderRadius: 2 }}>
              <Typography variant="subtitle1" fontWeight="medium" mb={2}>
                Элементы карточки
              </Typography>
              
              <FormControlLabel
                control={
                  <Switch
                    checked={settings.cardSettings?.enableFavorites}
                    onChange={handleCardSettingChange}
                    name="enableFavorites"
                  />
                }
                label={
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <Favorite fontSize="small" sx={{ mr: 1 }} />
                    <Typography>Кнопка "Избранное"</Typography>
                  </Box>
                }
              />
              
              <FormControlLabel
                control={
                  <Switch
                    checked={settings.cardSettings?.showCompanyLogo}
                    onChange={handleCardSettingChange}
                    name="showCompanyLogo"
                  />
                }
                label={
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <Badge fontSize="small" sx={{ mr: 1 }} />
                    <Typography>Логотип компании</Typography>
                  </Box>
                }
              />
              
              <FormControlLabel
                control={
                  <Switch
                    checked={settings.cardSettings?.showPrice}
                    onChange={handleCardSettingChange}
                    name="showPrice"
                  />
                }
                label={
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <Money fontSize="small" sx={{ mr: 1 }} />
                    <Typography>Отображать цену</Typography>
                  </Box>
                }
              />
              
              <FormControlLabel
                control={
                  <Switch
                    checked={settings.cardSettings?.showProgress}
                    onChange={handleCardSettingChange}
                    name="showProgress"
                  />
                }
                label={
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <ViewModule fontSize="small" sx={{ mr: 1 }} />
                    <Typography>Прогресс-бар</Typography>
                  </Box>
                }
              />
            </Paper>
          </Grid>
          
          <Grid size={{ xs: 12, md: 6 }}>
            <Paper sx={{ p: 3, borderRadius: 2 }}>
              <Typography variant="subtitle1" fontWeight="medium" mb={2}>
                Внешний вид карточки
              </Typography>
              
              <TextField
                fullWidth
                label="Скругление углов"
                name="cornerRadius"
                value={settings.cardSettings?.cornerRadius}
                onChange={handleCardSettingChange}
                margin="normal"
                helperText="Например: 20px, 12px и т.д."
              />
              
              <FormControlLabel
                control={
                  <Switch
                    checked={settings.cardSettings?.enableHoverEffects}
                    onChange={handleCardSettingChange}
                    name="enableHoverEffects"
                  />
                }
                label="Эффекты при наведении"
                sx={{ mt: 2, display: 'block' }}
              />
              
              <TextField
                fullWidth
                label="Тень карточки"
                name="cardElevation"
                select
                SelectProps={{ native: true }}
                value={settings.cardSettings?.cardElevation}
                onChange={handleCardSettingChange}
                margin="normal"
                helperText="Насколько выразительная тень у карточки"
              >
                <option value="low">Слабая</option>
                <option value="medium">Средняя</option>
                <option value="high">Сильная</option>
              </TextField>
            </Paper>
          </Grid>
          
          <Grid size={{ xs: 12 }}>
            <Paper sx={{ p: 3, borderRadius: 2, mt: 2 }}>
              <Typography variant="subtitle1" fontWeight="medium" mb={2}>
                Превью карточки с текущими настройками
              </Typography>
              
              <Alert severity="info" sx={{ mb: 2 }}>
                Изменения будут применены после сохранения настроек и перезагрузки страницы.
              </Alert>
              
              <Box sx={{ 
                border: '1px dashed rgba(0,0,0,0.1)', 
                borderRadius: 2, 
                p: 2, 
                display: 'flex',
                justifyContent: 'center'
              }}>
                <img 
                  src="/card-preview.png" 
                  alt="Превью карточки"
                  style={{ 
                    maxWidth: '100%', 
                    height: 'auto', 
                    maxHeight: 350,
                    borderRadius: 8,
                    opacity: 0.8
                  }}
                />
              </Box>
            </Paper>
          </Grid>
        </Grid>
      </TabPanel>
      
      {error && (
        <Alert severity="error" sx={{ mt: 3 }}>
          {error}
        </Alert>
      )}
      
      <Snackbar
        open={success}
        autoHideDuration={5000}
        onClose={handleCloseSnackbar}
        message="Настройки успешно сохранены"
      />
    </Paper>
  );
};

export default AppSettingsForm;
